import{c as s,cN as a,cG as n,cb as t,c8 as e,cf as i,cT as l,ce as p,cg as d,d as o}from"./chunks/framework.BlkIsu1j.js";const r=JSON.parse('{"title":"第 10 章：工作原理","description":"","frontmatter":{"title":"第 10 章：工作原理","outline":"deep","layout":"doc","prev":"/ai/claudecodenew/09-mode-switching","next":"/ai/claudecodenew/11-context-management","date":"2026-05-30T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecodenew/10-how-it-works.md","filePath":"ai/claudecodenew/10-how-it-works.md","lastUpdated":1780121796000}'),h={id:"frontmatter-title",tabindex:"-1"};const c=s({name:"ai/claudecodenew/10-how-it-works.md"},[["render",function(s,r,c,u,g,k){const b=a("vitepress-mermaid");return n(),t("div",null,[e("h1",h,[i(l(s.$frontmatter.title)+" ",1),r[0]||(r[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),r[1]||(r[1]=p('<p>前九章，我们学会了 Claude Code 的&quot;术&quot;——它能做什么、怎么用它完成日常开发任务。从本章开始，我们进入第三篇，掌握 Claude Code 的&quot;道&quot;——它为什么这样工作、内部机制如何运转、怎样利用这些理解让它为你发挥最大效能。</p><p>本章是第三篇的基石。当你理解了 Agent Loop、工具系统、上下文管理和权限模型的底层逻辑，你就从&quot;会用 Claude Code&quot;跨入了&quot;精通 Claude Code&quot;的阶段。你将能：</p><ul><li>预测 Claude 的下一步行为，而不是被动等待</li><li>在 Claude 卡住时精准介入，而不是茫然重试</li><li>设计更好的 CLAUDE.md 和项目结构，因为你知道 Claude 如何&quot;看&quot;你的项目</li><li>写出更高效的提示，因为你理解提示之后的整个执行链路</li></ul><blockquote><p><strong>本章目标</strong>：理解 Agent Loop 的完整执行流程、掌握每个工具的原理与选择逻辑、能阅读工具调用日志并判断 Claude 的工作状态、建立对 Claude Code 内部运作的完整心智模型。</p></blockquote><h2 id="_10-1-agent-loop-核心运转模型" tabindex="-1">10.1 Agent Loop：核心运转模型 <a class="header-anchor" href="#_10-1-agent-loop-核心运转模型" aria-label="Permalink to “10.1 Agent Loop：核心运转模型”">​</a></h2><p>Claude Code 的一切行为都围绕 <strong>Agent Loop</strong>（代理循环）展开。这不是一个抽象概念——每一次你发送消息，Claude Code 都会经历这个循环，直到任务完成、需要你输入、或触及上限。</p>',6)),d(b,{value:'flowchart TB\n    A["理解意图"] --\x3e B["制定计划"]\n    B --\x3e C["调用工具"]\n    C --\x3e D{"观察结果"}\n    D --\x3e|"未完成"| B\n    D --\x3e|"完成 / 需输入 / 达上限"| END["退出循环"]\n\n    style A fill:#e1f5fe\n    style B fill:#e8f5e9\n    style C fill:#fff3e0\n    style D fill:#f3e5f5\n    style END fill:#ffebee'}),r[2]||(r[2]=p('<p><img src="'+o+'" alt="Agentic Loop" loading="lazy"></p><h3 id="循环的五个阶段" tabindex="-1">循环的五个阶段 <a class="header-anchor" href="#循环的五个阶段" aria-label="Permalink to “循环的五个阶段”">​</a></h3><p><strong>阶段一：理解意图（Intent Understanding）</strong></p><p>当你发送&quot;帮我重构 src/api/auth.ts，把回调改成 async/await&quot;，Claude Code 不只是看到一串文字。它在理解层做了以下工作：</p><ol><li><strong>语义解析</strong>：识别核心动作是&quot;重构&quot;（不是新建、不是修复），目标是&quot;auth.ts&quot;，约束是&quot;回调改 async/await&quot;</li><li><strong>上下文注入</strong>：自动加载当前项目的 CLAUDE.md、git status、系统提示词中被注入的目录结构信息</li><li><strong>歧义消解</strong>：如果 auth.ts 中有多处回调模式，Claude 会优先读取文件确认范围</li><li><strong>风险评估</strong>：重构 auth 模块属于中高风险操作，需要确认权限</li></ol><p>这个阶段决定了后续所有行为的方向。如果意图理解出现偏差（比如把它当成&quot;新建一个 auth 模块&quot;），整个循环都会跑偏。</p><p><strong>阶段二：制定计划（Planning）</strong></p><p>Claude 不会一上来就改代码。它会先在&quot;思维&quot;中制定执行计划：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>计划示例:</span></span>\n<span class="line"><span>1. 用 Read 读取 src/api/auth.ts，理解当前回调结构</span></span>\n<span class="line"><span>2. 用 Grep 搜索项目中所有调用 auth 函数的地方（评估影响面）</span></span>\n<span class="line"><span>3. 逐个函数改写：callback(err, result) → try { result = await ... } catch(err)</span></span>\n<span class="line"><span>4. 用 Edit 工具逐个修改</span></span>\n<span class="line"><span>5. 用 Bash 运行测试确保没有破坏现有逻辑</span></span>\n<span class="line"><span>6. 向用户报告修改摘要</span></span></code></pre></div><p>这个计划不是写死的——每次迭代后 Claude 会根据结果调整。计划的质量直接决定了执行效率：好的计划让 Claude 用最少的工具调用完成任务，差的计划导致反复读写、来回修补。</p><p><strong>阶段三：调用工具（Tool Execution）</strong></p><p>这是你作为用户能看到的最直观的阶段。Claude 输出工具调用请求（JSON 格式），由 CLI/IDE 层在本地执行。你在聊天面板中看到的就是这个阶段的产物——Read 的代码块、Bash 的命令输出、Edit 的 diff 预览。</p><p>每次工具调用都是<strong>原子</strong>的：成功则返回结果，失败则返回错误信息。Claude 必须等待一个工具调用返回后，才能发起下一个（只有少数情况例外，如后台 Task）。</p><p><strong>阶段四：观察结果（Result Observation）</strong></p><p>这是循环的&quot;决策点&quot;。Claude 读取工具返回的结果，然后做出判断：</p><ul><li><strong>&quot;结果符合预期，任务完成&quot;</strong> → 退出循环，向你报告</li><li><strong>&quot;结果符合预期，但还有下一步&quot;</strong> → 回到阶段二，更新计划</li><li><strong>&quot;结果不符合预期&quot;</strong> → 回到阶段二，调整策略（比如换个搜索关键词、换个修改方式）</li><li><strong>&quot;需要用户决策&quot;</strong> → 暂停循环，弹窗请求你的输入</li><li><strong>&quot;遇到无法处理的情况&quot;</strong> → 退出循环，向你说明问题</li></ul><p>这个阶段考验的是 Claude 的&quot;自我评估&quot;能力。低质量的模型可能在结果不符合预期时仍然硬着头皮继续，而高质量的模型会及时调整方向。</p><p><strong>阶段五：迭代（Iteration）</strong></p><p>一次典型的对话中，Agent Loop 可能循环 5-50 次不等。简单的&quot;解释这段代码&quot;可能只需要 1-2 次循环（Read → 分析 → 输出），而&quot;重构整个模块&quot;可能需要几十次循环。</p><p>循环次数受以下因素影响：</p><ul><li><strong>任务复杂度</strong>：改动范围越大，循环越多</li><li><strong>上下文清晰度</strong>：项目结构越清晰，Claude 定位目标越精准，循环越少</li><li><strong>提示质量</strong>：指令越具体，Claude 越少走弯路</li><li><strong>模型能力</strong>：强模型能用更少的循环完成任务</li></ul><h3 id="你是谁-人在循环中的角色" tabindex="-1">你是谁：人在循环中的角色 <a class="header-anchor" href="#你是谁-人在循环中的角色" aria-label="Permalink to “你是谁：人在循环中的角色”">​</a></h3><p>Agent Loop 是<strong>自主进行</strong>的，但你不是旁观者。你在循环中扮演三个关键角色：</p>',23)),d(b,{value:'flowchart LR\n    P["你的提示"]\n\n    subgraph Loop["agentic loop"]\n        direction LR\n        GC["收集上下文"] --\x3e TA["执行操作"] --\x3e VR["验证结果"]\n        VR -."循环".-> GC\n    end\n\n    D["完成"]\n    H["你：中断、引导<br>或补充上下文"]\n\n    P --\x3e GC\n    VR --\x3e D\n    H -."介入".-> TA\n\n    style P fill:#e8e8e4,stroke:#999\n    style D fill:#e8e8e4,stroke:#999\n    style GC fill:#d4e4d8,stroke:#8ab\n    style TA fill:#d4e4d8,stroke:#8ab\n    style VR fill:#d4e4d8,stroke:#8ab\n    style H fill:#fdf6f2,stroke:#d4a27f'}),r[3]||(r[3]=p('<ol><li><strong>启动者（Initiator）</strong>：你发出提示，设定目标方向和约束条件</li><li><strong>监督者（Supervisor）</strong>：你在权限弹窗中批准或拒绝高风险操作，在 Claude 跑偏时纠正</li><li><strong>验收者（Reviewer）</strong>：你审查最终结果，决定接受还是要求修改</li></ol><p>这三个角色不是你&quot;可以做&quot;的事情，而是 Claude Code <strong>设计上就依赖你承担</strong>的角色。如果你只当&quot;启动者&quot;而放弃监督和验收，就等于把方向盘完全交给了一个没有业务判断力的助手。</p><h3 id="一个真实的循环示例" tabindex="-1">一个真实的循环示例 <a class="header-anchor" href="#一个真实的循环示例" aria-label="Permalink to “一个真实的循环示例”">​</a></h3><p>假设你输入：&quot;给 README.md 加一个安装步骤说明&quot;。</p><table tabindex="0"><thead><tr><th>循环次数</th><th>阶段</th><th>Claude 行为</th><th>你的角色</th></tr></thead><tbody><tr><td>1</td><td>理解意图</td><td>识别目标文件 README.md，任务类型为&quot;文档编辑&quot;</td><td>—</td></tr><tr><td>1</td><td>制定计划</td><td>计划：先读文件，再编辑插入内容</td><td>—</td></tr><tr><td>1</td><td>调用工具</td><td>Read README.md</td><td>—</td></tr><tr><td>1</td><td>观察结果</td><td>读到文件内容，找到合适插入位置</td><td>—</td></tr><tr><td>2</td><td>制定计划</td><td>在&quot;Usage&quot;章节前插入&quot;Installation&quot;章节</td><td>—</td></tr><tr><td>2</td><td>调用工具</td><td>Edit README.md（插入 Installation 内容）</td><td>可能触发权限确认</td></tr><tr><td>2</td><td>观察结果</td><td>Edit 成功，文件已更新</td><td>—</td></tr><tr><td>3</td><td>制定计划</td><td>验证：重新读取文件确认内容正确</td><td>—</td></tr><tr><td>3</td><td>调用工具</td><td>Read README.md</td><td>—</td></tr><tr><td>3</td><td>观察结果</td><td>内容正确，格式无误</td><td>—</td></tr><tr><td>—</td><td>退出循环</td><td>向你报告：&quot;已在 README.md 中添加安装步骤&quot;</td><td>审查结果</td></tr></tbody></table><p>一个看似简单的&quot;加一句话&quot;操作，背后 Claude 经历了 3 次循环。理解这一点，你就能理解为什么复杂任务需要那么多工具调用——这不是效率低，而是<strong>通过小步验证来保证质量</strong>。</p><h2 id="_10-2-工具系统详解" tabindex="-1">10.2 工具系统详解 <a class="header-anchor" href="#_10-2-工具系统详解" aria-label="Permalink to “10.2 工具系统详解”">​</a></h2><p>工具是 Claude Code 与现实世界交互的&quot;手脚&quot;。没有工具，Claude Code 只是一只关在笼子里的聪明鹦鹉——能说会道，但碰不到你的代码。有了工具，它就成了能实际行动的 Agent。</p><p>理解每个工具的原理、使用场景和限制，是你精准使用 Claude Code 的基础。</p><h3 id="_10-2-1-文件工具" tabindex="-1">10.2.1 文件工具 <a class="header-anchor" href="#_10-2-1-文件工具" aria-label="Permalink to “10.2.1 文件工具”">​</a></h3><p>文件工具是 Claude Code 最常用的工具组。它们直接操作你项目中的文件，是 Claude 理解代码和修改代码的基础。</p><table tabindex="0"><thead><tr><th>工具</th><th>作用</th><th>典型场景</th><th>何时触发</th><th>返回内容</th><th>限制与须知</th></tr></thead><tbody><tr><td><strong>Read</strong></td><td>读取文件内容</td><td>理解代码、查看配置、确认修改结果</td><td>需要了解文件内容时；几乎每次修改前都会先用 Read</td><td>带行号的文件内容（如 <code>cat -n</code>）</td><td>大文件可能只读部分（默认约 2000 行）；图片文件返回视觉描述；PDF 需指定页码范围</td></tr><tr><td><strong>Write</strong></td><td>创建或覆写文件</td><td>新建文件、完全重写内容</td><td>需要创建全新文件，或文件内容需要彻底替换时</td><td>操作确认信息</td><td>会覆盖已有内容而不警告；Write 前必须先 Read 同名文件（系统强制）；不适合局部修改</td></tr><tr><td><strong>Edit</strong></td><td>精准文本替换</td><td>修改文件特定位置、插入代码片段</td><td>需要局部修改，不改动其他部分时；这是最常用的修改工具</td><td>修改确认信息（成功/失败）</td><td>需要 exact match（精确匹配原文）；如果旧文本不唯一或找不到，编辑会失败；不支持正则替换</td></tr><tr><td><strong>Bash</strong></td><td>执行 Shell 命令</td><td>运行构建、测试、Git 操作、安装依赖</td><td>需要执行任何 Shell 命令时</td><td>stdout + stderr + exit code</td><td>高风险命令需用户确认（如 rm -rf、git push --force、sudo）；环境非持久化（每个命令在新 Shell 中执行）；超时默认 120 秒</td></tr><tr><td><strong>Glob</strong></td><td>文件模式匹配</td><td>按通配符查找文件（如 <code>**/*.test.ts</code>）</td><td>需要找到满足特定命名模式的一组文件时</td><td>匹配的文件路径列表</td><td>不支持正则，仅支持 glob 通配符（*、**、?、[]）</td></tr><tr><td><strong>Grep</strong></td><td>内容搜索</td><td>搜索代码中的特定字符串、正则模式</td><td>需要找到包含特定代码模式的所有文件时</td><td>匹配的行及所在文件和行号</td><td>大项目可能返回大量结果；正则语法与标准 grep 一致</td></tr></tbody></table><p><strong>Read 的工作方式</strong>：Read 是 Claude Code 使用最频繁的工具。它返回的内容带行号前缀，Claude 后续做 Edit 时可以直接引用行号范围。对于超长文件，Claude 会分段读取——先读头部了解结构，再根据需要跳到特定区域。如果你发现 Claude 反复读同一个文件的不同部分，说明它正在拼凑对文件全貌的理解。</p><p><strong>Edit 的精确匹配机制</strong>：Edit 不是&quot;找到相似内容然后替换&quot;，而是<strong>严格字符串匹配</strong>。这意味着：</p><ul><li>空格和缩进必须完全相同</li><li>换行符格式必须一致</li><li>old_string 必须是文件中的唯一片段（除非 <code>replace_all: true</code>）</li></ul><p>这是 Edit 最常见的失败原因——Claude 以为文件中有某段代码，但实际上缩进差了 2 个空格。</p><p><strong>Bash 的执行模型</strong>：每次 Bash 调用都是<strong>隔离的 Shell 会话</strong>。状态（环境变量、当前目录、后台进程）不会在两次 Bash 调用之间保留。如果你需要多步命令共享状态，要么用 <code>&amp;&amp;</code> 串联，要么用分号 <code>;</code> 在同一次调用中执行。此外，Bash 默认在项目根目录执行，而非你当前在终端中的目录。</p><h3 id="_10-2-2-搜索工具-glob-与-grep" tabindex="-1">10.2.2 搜索工具：Glob 与 Grep <a class="header-anchor" href="#_10-2-2-搜索工具-glob-与-grep" aria-label="Permalink to “10.2.2 搜索工具：Glob 与 Grep”">​</a></h3><p>这两个工具看似简单，但在 Claude 的&quot;理解项目&quot;流程中至关重要。Claude 不依赖 IDE 的项目索引——它通过 Glob 和 Grep 来发现项目结构。</p><p><strong>Glob 的典型使用模式</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>场景一：查找所有测试文件</span></span>\n<span class="line"><span>Claude 调用: Glob pattern=&quot;**/*.test.ts&quot;</span></span>\n<span class="line"><span>用途：确定测试文件分布，决定修改哪些测试</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>场景二：理解项目结构</span></span>\n<span class="line"><span>Claude 调用: Glob pattern=&quot;src/**/*&quot;</span></span>\n<span class="line"><span>用途：快速了解 src 目录下的文件布局</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>场景三：查找特定类型文件</span></span>\n<span class="line"><span>Claude 调用: Glob pattern=&quot;**/*.config.*&quot;</span></span>\n<span class="line"><span>用途：找到所有配置文件，理解项目配置体系</span></span></code></pre></div><p><strong>Grep 的典型使用模式</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>场景一：找到函数的所有调用点</span></span>\n<span class="line"><span>Claude 调用: Grep pattern=&quot;authenticate\\(&quot;</span></span>\n<span class="line"><span>用途：重构前评估影响范围</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>场景二：搜索错误日志中的关键词</span></span>\n<span class="line"><span>Claude 调用: Grep pattern=&quot;ERR_MODULE_NOT_FOUND&quot;</span></span>\n<span class="line"><span>用途：定位错误来源</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>场景三：找到所有 TODO 注释</span></span>\n<span class="line"><span>Claude 调用: Grep pattern=&quot;TODO|FIXME|HACK&quot;</span></span>\n<span class="line"><span>用途：发现遗留的技术债务</span></span></code></pre></div><p><strong>组合使用</strong>：Claude 经常先 Glob 确定范围，再 Grep 精确定位——这和人类开发者的工作流完全一致。</p><h3 id="_10-2-3-高级工具" tabindex="-1">10.2.3 高级工具 <a class="header-anchor" href="#_10-2-3-高级工具" aria-label="Permalink to “10.2.3 高级工具”">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>作用</th><th>典型场景</th><th>何时触发</th><th>返回内容</th><th>限制与须知</th></tr></thead><tbody><tr><td><strong>Agent</strong></td><td>启动子代理，独立执行子任务</td><td>并行执行多个独立任务、大规模代码搜索</td><td>任务可拆分为互不依赖的子任务时</td><td>子代理的完整输出</td><td>子代理有独立上下文，不共享主对话状态；子代理之间不能通信</td></tr><tr><td><strong>WebSearch</strong></td><td>搜索网络</td><td>获取最新技术文档、API 变更、版本兼容性问题</td><td>需要当前信息（训练数据截止后的内容）时</td><td>搜索结果列表（标题 + URL + 摘要）</td><td>仅限美国区域搜索结果；可能需要用户确认</td></tr><tr><td><strong>WebFetch</strong></td><td>抓取网页内容并提取</td><td>查阅在线文档、阅读 GitHub Issue、获取 API 参考</td><td>需要获取特定 URL 的完整内容时</td><td>页面内容的 Markdown 格式提取</td><td>无法处理需认证的页面；跨域重定向不会自动跟随；结果缓存 15 分钟</td></tr><tr><td><strong>TodoWrite</strong></td><td>管理任务列表</td><td>跟踪复杂多步骤任务、向用户展示进度</td><td>任务超过 3 个独立步骤时</td><td>任务列表更新确认</td><td>是 Claude 内部使用，但你可以在聊天面板中看到</td></tr><tr><td><strong>TaskOutput</strong></td><td>获取后台任务结果</td><td>查询异步执行的后台命令状态</td><td>启动了后台 Bash 任务后需要查看结果时</td><td>后台任务的 stdout/stderr</td><td>仅用于后台任务；前台任务直接返回结果</td></tr><tr><td><strong>NotebookEdit</strong></td><td>编辑 Jupyter Notebook</td><td>数据科学场景中修改 notebook 单元格</td><td>操作 <code>.ipynb</code> 文件时</td><td>单元格编辑确认</td><td>仅支持 Jupyter Notebook 格式；需要指定 cell 编号</td></tr><tr><td><strong>Task</strong></td><td>启动后台长时间任务</td><td>运行可能超时的命令、并行执行</td><td>命令预计运行时间超过默认超时（120秒）时</td><td>任务 ID，后续用 TaskOutput 查询</td><td>后台运行，不阻塞对话；需要主动查询结果</td></tr></tbody></table><p><strong>Agent 工具的核心价值</strong>：Agent 工具是 Claude Code 实现并行工作流的关键。当你要求&quot;同时修复所有测试文件的 lint 错误&quot;时，Claude 可以启动多个子代理，每个负责一个测试文件。每个子代理在自己的沙箱中运行完整的 Agent Loop，独立完成任务后返回结果。</p><p>Agent 工具的使用原则：</p><ul><li>子任务之间必须<strong>无依赖关系</strong>——子代理不共享上下文</li><li>每个子代理消耗独立的 token 配额</li><li>子代理有与主对话相同的工具权限（受权限配置约束）</li></ul><p><strong>WebSearch 与 WebFetch 的配合</strong>：这两个工具经常协同工作——先用 WebSearch 找到相关页面，再用 WebFetch 获取详细内容。例如：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>你：&quot;这个项目的 React 版本和最新版 React 有什么 Breaking Changes？&quot;</span></span>\n<span class="line"><span>Claude: WebSearch(query=&quot;React latest version breaking changes 2026&quot;)</span></span>\n<span class="line"><span>        → 找到官方 Migration Guide URL</span></span>\n<span class="line"><span>        WebFetch(url=&quot;https://react.dev/blog/...&quot;)</span></span>\n<span class="line"><span>        → 提取完整变更列表</span></span></code></pre></div><h3 id="_10-2-4-工具选择决策树" tabindex="-1">10.2.4 工具选择决策树 <a class="header-anchor" href="#_10-2-4-工具选择决策树" aria-label="Permalink to “10.2.4 工具选择决策树”">​</a></h3><p>Claude 如何决定使用哪个工具？以下决策逻辑可以帮助你理解（和预测）它的行为：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>需要获取信息？</span></span>\n<span class="line"><span>├── 文件内容 → Read</span></span>\n<span class="line"><span>├── 文件位置 → Glob</span></span>\n<span class="line"><span>├── 代码中的模式 → Grep</span></span>\n<span class="line"><span>├── 在线信息 → WebSearch → WebFetch</span></span>\n<span class="line"><span>└── 后台任务状态 → TaskOutput</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>需要修改内容？</span></span>\n<span class="line"><span>├── 新建文件 → Write</span></span>\n<span class="line"><span>├── 局部修改 → Edit</span></span>\n<span class="line"><span>└── 执行命令 → Bash</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>需要组织工作？</span></span>\n<span class="line"><span>├── 多步骤任务 → TodoWrite</span></span>\n<span class="line"><span>├── 并行子任务 → Agent</span></span>\n<span class="line"><span>└── 长时间命令 → Task</span></span></code></pre></div><p>理解这个决策树，你就能预判 Claude 的行为。当你发现 Claude 选择了&quot;错误&quot;的工具——比如用 Read 去搜代码而不是用 Grep——你可以直接告诉它&quot;用 Grep 搜索&quot;，它会立即调整。</p><h2 id="_10-3-工具调用机制" tabindex="-1">10.3 工具调用机制 <a class="header-anchor" href="#_10-3-工具调用机制" aria-label="Permalink to “10.3 工具调用机制”">​</a></h2><p>工具调用不是 Claude Code 独有的概念——它是 Anthropic API 的标准能力。但 Claude Code 对工具调用的处理方式决定了你的使用体验。理解这个机制，你就能读懂聊天面板中的工具调用日志，也能在出现问题时精准定位。</p><h3 id="调用流程" tabindex="-1">调用流程 <a class="header-anchor" href="#调用流程" aria-label="Permalink to “调用流程”">​</a></h3><p>每次 Claude Code 决定使用工具时，经历以下流程：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>模型                     CLI/IDE 层                 你的电脑</span></span>\n<span class="line"><span> │                          │                         │</span></span>\n<span class="line"><span> │  1. 输出工具调用请求      │                         │</span></span>\n<span class="line"><span> │  (JSON 格式)             │                         │</span></span>\n<span class="line"><span> │─────────────────────────&gt;│                         │</span></span>\n<span class="line"><span> │                          │  2. 解析 JSON            │</span></span>\n<span class="line"><span> │                          │  3. 权限检查             │</span></span>\n<span class="line"><span> │                          │     ├── 自动允许 → 直接执行│</span></span>\n<span class="line"><span> │                          │     └── 需确认 → 弹窗等待 │</span></span>\n<span class="line"><span> │                          │                         │</span></span>\n<span class="line"><span> │                          │  4. 执行工具           │</span></span>\n<span class="line"><span> │                          │─────────────────────────&gt;│</span></span>\n<span class="line"><span> │                          │                         │</span></span>\n<span class="line"><span> │                          │  5. 返回执行结果        │</span></span>\n<span class="line"><span> │                          │&lt;─────────────────────────│</span></span>\n<span class="line"><span> │                          │                         │</span></span>\n<span class="line"><span> │  6. 分析结果              │                         │</span></span>\n<span class="line"><span> │  7. 决定下一步            │                         │</span></span>\n<span class="line"><span> │&lt;─────────────────────────│                         │</span></span></code></pre></div><h3 id="json-工具调用格式" tabindex="-1">JSON 工具调用格式 <a class="header-anchor" href="#json-工具调用格式" aria-label="Permalink to “JSON 工具调用格式”">​</a></h3><p>每种工具的调用请求都是一个结构化的 JSON 对象。以下是几个典型示例：</p><p><strong>Read 调用</strong>：</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Read&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;parameters&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;file_path&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/home/user/project/src/api/auth.ts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;offset&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">45</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;limit&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">60</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Edit 调用</strong>：</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Edit&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;parameters&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;file_path&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/home/user/project/src/api/auth.ts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;old_string&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;function authenticate(user, password, callback) {&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;new_string&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;async function authenticate(user, password) {&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Bash 调用</strong>：</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;parameters&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cd /home/user/project &amp;&amp; pnpm test -- --testPathPattern=auth&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Run auth-related tests&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;timeout&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">120000</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>你不需要手动编写这些 JSON——Claude 自动生成。但理解这个格式有助于你阅读工具调用日志。</p><h3 id="权限检查的位置" tabindex="-1">权限检查的位置 <a class="header-anchor" href="#权限检查的位置" aria-label="Permalink to “权限检查的位置”">​</a></h3><p>在调用流程的第 3 步，CLI/IDE 层会对照你的权限配置（四层配置体系，详见第 14 章）做出判断：</p><ul><li><strong>匹配 allow 规则</strong> → 自动执行，不弹窗</li><li><strong>匹配 deny 规则</strong> → 拒绝执行，Claude 收到&quot;Permission denied&quot;并尝试其他方式</li><li><strong>匹配 ask 规则</strong> → 弹出确认窗口，等待你的 Allow/Deny 决策</li><li><strong>无匹配规则</strong> → 使用默认策略（Read/Glob/Grep 自动允许；Edit/Write 默认确认；高危 Bash 始终确认）</li></ul><p>权限检查发生在工具<strong>执行前</strong>，而非调用前——Claude 已经做出了调用决策，只是被权限关卡拦截。这解释了为什么你在权限弹窗中看到的工具调用信息已经很具体。</p><h3 id="结果返回格式" tabindex="-1">结果返回格式 <a class="header-anchor" href="#结果返回格式" aria-label="Permalink to “结果返回格式”">​</a></h3><p>工具执行结果返回给模型时，包含：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>工具名: Read</span></span>\n<span class="line"><span>状态: success / error</span></span>\n<span class="line"><span>输出: &lt;工具的具体输出内容&gt;</span></span>\n<span class="line"><span>耗时: 234ms</span></span></code></pre></div><p>对于 <strong>error 状态</strong>，Claude 会：</p><ol><li>读取错误信息</li><li>判断错误原因（权限不足？文件不存在？语法错误？）</li><li>调整方案（换个工具？换个参数？向你求助？）</li></ol><p>这就是 Claude &quot;自我纠正&quot;能力的关键——它不是一次调用失败就放弃，而是像人类开发者一样根据错误信息调整策略。</p><h3 id="工具调用的组合模式" tabindex="-1">工具调用的组合模式 <a class="header-anchor" href="#工具调用的组合模式" aria-label="Permalink to “工具调用的组合模式”">​</a></h3><p>在实际对话中，工具调用很少单独使用。以下是几种常见的组合模式：</p><p><strong>模式一：Read → Edit → Read（理解-修改-验证）</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Read auth.ts      → 理解当前代码</span></span>\n<span class="line"><span>Edit auth.ts      → 修改特定函数</span></span>\n<span class="line"><span>Read auth.ts      → 验证修改正确</span></span></code></pre></div><p><strong>模式二：Glob → Grep → Read（定位-搜索-细读）</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Glob src/**/*.ts   → 找到所有 TypeScript 文件</span></span>\n<span class="line"><span>Grep &quot;authService&quot; → 在结果中搜索引用</span></span>\n<span class="line"><span>Read 命中文件       → 仔细阅读关键文件</span></span></code></pre></div><p><strong>模式三：Bash → Read → Edit（执行-分析-修复）</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Bash pnpm test     → 运行测试 → 测试失败</span></span>\n<span class="line"><span>Read 错误日志      → 理解失败原因</span></span>\n<span class="line"><span>Edit 源代码        → 修复问题</span></span>\n<span class="line"><span>Bash pnpm test     → 再次运行 → 测试通过</span></span></code></pre></div><p>识别这些模式，你就能快速判断 Claude 当前处于什么工作阶段。</p><h2 id="_10-4-从输入到输出的完整生命周期" tabindex="-1">10.4 从输入到输出的完整生命周期 <a class="header-anchor" href="#_10-4-从输入到输出的完整生命周期" aria-label="Permalink to “10.4 从输入到输出的完整生命周期”">​</a></h2><p>你发出一个请求，Claude Code 做了什么？本节跟踪一个完整请求从输入到输出的每一步。以&quot;帮我重构 src/api/auth.ts，把回调改成 async/await&quot;为例。</p><h3 id="生命周期时间线" tabindex="-1">生命周期时间线 <a class="header-anchor" href="#生命周期时间线" aria-label="Permalink to “生命周期时间线”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>时间轴</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── 0ms   [你] 在聊天框输入：&quot;帮我重构 src/api/auth.ts，把回调改成 async/await&quot;</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── 0ms   [系统] 收集上下文</span></span>\n<span class="line"><span> │          ├── 加载 System Prompt（行为准则、平台信息、工具说明）</span></span>\n<span class="line"><span> │          ├── 读取 CLAUDE.md（项目架构、命名规范、常用命令）</span></span>\n<span class="line"><span> │          ├── 读取 Git Status（当前分支、未提交变更、远程状态）</span></span>\n<span class="line"><span> │          └── 注入 Memory（之前的偏好和约定）</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~200ms [模型] 理解意图</span></span>\n<span class="line"><span> │          ├── 语义分析：任务类型=&quot;重构&quot;，目标=&quot;auth.ts&quot;，约束=&quot;回调改 async/await&quot;</span></span>\n<span class="line"><span> │          ├── 上下文匹配：auth.ts 属于 API 层，可能依赖数据库模块和中间件</span></span>\n<span class="line"><span> │          └── 风险评估：auth 是高敏感模块，需要谨慎操作</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~500ms [模型] 制定初步计划</span></span>\n<span class="line"><span> │          ├── 步骤1：Read auth.ts 完整内容</span></span>\n<span class="line"><span> │          ├── 步骤2：Grep 搜索所有调用 auth 的地方</span></span>\n<span class="line"><span> │          ├── 步骤3：逐个识别回调模式的函数</span></span>\n<span class="line"><span> │          ├── 步骤4：Edit 逐个改写</span></span>\n<span class="line"><span> │          └── 步骤5：Bash 运行测试验证</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~600ms [工具] Read src/api/auth.ts</span></span>\n<span class="line"><span> │          ├── 权限检查：Read 属于自动允许级别</span></span>\n<span class="line"><span> │          ├── 文件系统：读取 /home/user/project/src/api/auth.ts</span></span>\n<span class="line"><span> │          └── 返回：带行号的 320 行代码</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~800ms [模型] 分析文件结构</span></span>\n<span class="line"><span> │          ├── 识别出 8 个导出函数</span></span>\n<span class="line"><span> │          ├── 其中 4 个使用了 callback 模式</span></span>\n<span class="line"><span> │          │   ├── authenticate(user, pass, callback)</span></span>\n<span class="line"><span> │          │   ├── refreshToken(token, callback)</span></span>\n<span class="line"><span> │          │   ├── revokeToken(token, callback)</span></span>\n<span class="line"><span> │          │   └── validateSession(sessionId, callback)</span></span>\n<span class="line"><span> │          ├── 理解错误处理模式：callback(err, result)</span></span>\n<span class="line"><span> │          └── 决定改写策略：async function + try/catch</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~900ms [工具] Grep pattern=&quot;authenticate\\(|refreshToken\\(|revokeToken\\(|validateSession\\(&quot;</span></span>\n<span class="line"><span> │          ├── 权限检查：Grep 属于自动允许级别</span></span>\n<span class="line"><span> │          ├── 执行搜索：遍历 src/ 目录</span></span>\n<span class="line"><span> │          └── 返回：12 处调用，分布在 src/api/、src/middleware/、src/routes/</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~1100ms [模型] 评估影响面</span></span>\n<span class="line"><span> │          ├── 所有调用方都需要更新（从 callback 改为 await）</span></span>\n<span class="line"><span> │          ├── middleware/auth.ts 的改动最复杂（有条件分支）</span></span>\n<span class="line"><span> │          └── 更新计划：先改 auth.ts 定义，再批量更新调用方</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~1200ms [工具] Edit auth.ts（第1处：authenticate 函数签名）</span></span>\n<span class="line"><span> │          ├── 权限检查：Edit 需用户确认 → 弹出权限窗口</span></span>\n<span class="line"><span> │          ├── [你] 看到 diff 预览，点击 Allow</span></span>\n<span class="line"><span> │          ├── 执行替换：callback 签名 → async function</span></span>\n<span class="line"><span> │          └── 返回：success</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~1400ms [工具] Edit auth.ts（第2处：authenticate 函数体）</span></span>\n<span class="line"><span> │          ├── 权限检查：在 Ask 模式下，每次 Edit 都需确认</span></span>\n<span class="line"><span> │          ├── [你] Allow</span></span>\n<span class="line"><span> │          ├── 执行替换：callback(err, user) → return user</span></span>\n<span class="line"><span> │          └── 返回：success</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ...重复 6 次 Edit 操作...</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~4000ms [工具] Edit auth.ts（第8处：新增 try/catch 包裹）</span></span>\n<span class="line"><span> │          └── 返回：success</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~4100ms [工具] Read auth.ts（重新读取，验证修改正确）</span></span>\n<span class="line"><span> │          └── 返回：修改后的完整文件</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~4300ms [模型] 验证 auth.ts 修改</span></span>\n<span class="line"><span> │          ├── 检查所有 4 个函数已正确改写</span></span>\n<span class="line"><span> │          ├── 检查 try/catch 覆盖所有错误路径</span></span>\n<span class="line"><span> │          └── 发现：validateSession 缺少数据库连接失败的异常处理 → 补充 Edit</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ...继续迭代调用方文件的修改...</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~12000ms [模型] 所有修改完成</span></span>\n<span class="line"><span> │          ├── 最终验证：重新 Read 所有修改过的文件</span></span>\n<span class="line"><span> │          ├── 确认无遗漏</span></span>\n<span class="line"><span> │          └── 生成修改摘要</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~12500ms [工具] Bash &quot;cd /home/user/project &amp;&amp; pnpm test&quot;</span></span>\n<span class="line"><span> │          ├── 权限检查：Bash 运行测试，需确认或匹配 allow 规则</span></span>\n<span class="line"><span> │          ├── [你] 已配置 &quot;allow&quot;: [&quot;Bash(pnpm:test)&quot;] → 自动允许</span></span>\n<span class="line"><span> │          └── 返回：Test Suites: 8 passed, 0 failed</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> ├── ~13000ms [模型] 最终确认</span></span>\n<span class="line"><span> │          └── 所有测试通过，重构成功</span></span>\n<span class="line"><span> │</span></span>\n<span class="line"><span> └── ~13200ms [你] 看到报告：</span></span>\n<span class="line"><span>            &quot;已完成 auth.ts 的回调转 async/await 重构：</span></span>\n<span class="line"><span>             - 修改 4 个函数定义（authenticate, refreshToken, revokeToken, validateSession）</span></span>\n<span class="line"><span>             - 更新 12 处调用点（middleware/auth.ts, routes/session.ts, ...）</span></span>\n<span class="line"><span>             - 所有 8 个测试套件通过</span></span>\n<span class="line"><span>             是否需要进一步的调整？&quot;</span></span></code></pre></div><h3 id="生命周期中的关键节点" tabindex="-1">生命周期中的关键节点 <a class="header-anchor" href="#生命周期中的关键节点" aria-label="Permalink to “生命周期中的关键节点”">​</a></h3><p>从这个时间线中，你可以识别出几个关键的&quot;接入点&quot;——在这些节点上，你的干预最有效：</p><ol><li><p><strong>计划阶段（~500ms）</strong>：如果你对计划有异议，立即在权限弹窗中 Deny 并给出修正指令。这是成本最低的纠偏时机。</p></li><li><p><strong>权限检查点（每个 Edit/Bash 调用前）</strong>：这是你逐步骤审查的机会。不要一路 Allow——至少看前 2-3 个 Edit 确认方向正确。</p></li><li><p><strong>自我纠错点（~4300ms）</strong>：注意 Claude 在读取自己的输出后发现并修复了遗漏（validateSession 缺少异常处理）。这说明它在做 self-review。如果你发现它忽略了某个明显问题，可以提醒它&quot;再检查一下&quot;。</p></li><li><p><strong>最终验证点（~12000ms）</strong>：测试通过不代表完全正确。功能测试可能没覆盖边界情况。你的最终审查仍然是不可或缺的。</p></li></ol><h2 id="_10-5-理解工具调用日志" tabindex="-1">10.5 理解工具调用日志 <a class="header-anchor" href="#_10-5-理解工具调用日志" aria-label="Permalink to “10.5 理解工具调用日志”">​</a></h2><p>在 VSCode 的聊天面板中，每一次工具调用都有一条可见的日志记录。学会阅读这些日志，是判断 Claude 工作状态的基础技能。</p><h3 id="日志的结构" tabindex="-1">日志的结构 <a class="header-anchor" href="#日志的结构" aria-label="Permalink to “日志的结构”">​</a></h3><p>一条典型的工具调用日志包含以下信息：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─ Tool: Read ──────────────────────────────┐</span></span>\n<span class="line"><span>│ 📄 文件: src/api/auth.ts                   │</span></span>\n<span class="line"><span>│ 📏 范围: 行 45-104 (共 320 行)              │</span></span>\n<span class="line"><span>│ ⏱️  耗时: 234ms                            │</span></span>\n<span class="line"><span>│ 🔓 权限: 自动允许                           │</span></span>\n<span class="line"><span>│ ✅ 状态: success                           │</span></span>\n<span class="line"><span>└────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="各类工具的日志特征" tabindex="-1">各类工具的日志特征 <a class="header-anchor" href="#各类工具的日志特征" aria-label="Permalink to “各类工具的日志特征”">​</a></h3><p><strong>Read 日志特征</strong>：最频繁出现。注意它的读取范围——如果 Claude 反复读同一文件的不同区域，说明它正在拼凑理解。如果它反复读同一文件的<strong>同一区域</strong>，说明它可能陷入了&quot;读-不理解-再读&quot;的死循环。</p><p><strong>Edit 日志特征</strong>：每次 Edit 都会展示 diff preview。关键信息：</p><ul><li>修改的文件路径</li><li>替换的文本摘要（old → new）</li><li>替换的行数</li><li>权限确认状态（Allowed / Denied / Auto-allowed）</li></ul><p><strong>Bash 日志特征</strong>：</p><ul><li>执行的完整命令</li><li>exit code（0 = 成功，非 0 = 失败）</li><li>stdout 内容</li><li>stderr 内容（如果有）</li><li>执行耗时</li></ul><p><strong>错误日志的特殊标记</strong>：当工具调用失败时，日志会显示：</p><ul><li>❌ 错误类型（FileNotFound / PermissionDenied / Timeout / ...）</li><li>❌ 错误详情</li><li>🔄 Claude 的应对：调整参数重试 / 换用其他工具 / 请求用户帮助</li></ul><h3 id="识别异常模式" tabindex="-1">识别异常模式 <a class="header-anchor" href="#识别异常模式" aria-label="Permalink to “识别异常模式”">​</a></h3><p>通过日志，你可以识别以下异常模式：</p><p><strong>模式一：重复调用（Stuck Loop）</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Read auth.ts (行 1-100)</span></span>\n<span class="line"><span>Read auth.ts (行 1-100)  ← 相同调用，重复了！</span></span>\n<span class="line"><span>Read auth.ts (行 1-100)  ← 第三次...</span></span></code></pre></div><p><strong>含义</strong>：Claude 在重复相同的操作，可能因为：</p><ul><li>输出被截断，它不记得已经读过</li><li>对结果不满意但不知道如何调整</li><li>上下文窗口接近限制，出现&quot;健忘&quot;</li></ul><p><strong>你的应对</strong>：直接告诉它&quot;你已经读过 auth.ts 了，请继续下一步&quot;。</p><p><strong>模式二：频繁切换（Thrashing）</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Read auth.ts</span></span>\n<span class="line"><span>Read middleware.ts</span></span>\n<span class="line"><span>Read auth.ts        ← 又回来读</span></span>\n<span class="line"><span>Read routes.ts</span></span>\n<span class="line"><span>Read auth.ts        ← 第三次</span></span></code></pre></div><p><strong>含义</strong>：Claude 在多个文件间来回跳转，但无法形成完整理解。可能是因为文件间的关系比它预期的更复杂。</p><p><strong>你的应对</strong>：提供结构信息——&quot;auth.ts 被 middleware/auth.ts 和 routes/session.ts 调用，先看这三个文件就够了&quot;。</p><p><strong>模式三：过度搜索（Search Obsession）</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Grep &quot;authenticate&quot;</span></span>\n<span class="line"><span>Grep &quot;authenticate\\(.*callback\\)&quot;</span></span>\n<span class="line"><span>Grep &quot;auth.*callback&quot;</span></span>\n<span class="line"><span>Grep &quot;callback.*auth&quot;</span></span></code></pre></div><p><strong>含义</strong>：Claude 不确定用什么搜索模式能找到目标，不断更换关键词尝试。</p><p><strong>你的应对</strong>：直接告诉它精确的搜索词，或告诉它目标文件路径。</p><p><strong>模式四：健康的执行流</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Read auth.ts</span></span>\n<span class="line"><span>Grep &quot;authenticate\\(&quot;</span></span>\n<span class="line"><span>Read middleware/auth.ts  (grep 命中)</span></span>\n<span class="line"><span>Read routes/session.ts   (grep 命中)</span></span>\n<span class="line"><span>Edit auth.ts</span></span>\n<span class="line"><span>Edit middleware/auth.ts</span></span>\n<span class="line"><span>Read auth.ts  (验证)</span></span>\n<span class="line"><span>Bash pnpm test</span></span></code></pre></div><p><strong>含义</strong>：工作流健康——先理解，再搜索影响面，再有条理地修改，最后验证。这是你应该看到的模式。</p><h3 id="如何利用日志优化协作" tabindex="-1">如何利用日志优化协作 <a class="header-anchor" href="#如何利用日志优化协作" aria-label="Permalink to “如何利用日志优化协作”">​</a></h3><ol><li><strong>关注重复模式</strong>：看到 3 次以上相同工具调用，立即介入</li><li><strong>关注耗时</strong>：如果某个工具调用耗时异常（如超过 10 秒的 Read），可能是文件太大或网络问题</li><li><strong>关注错误恢复</strong>：观察 Claude 从错误中恢复的策略——如果它调整得好（如 Read 失败后换用 Grep 定位），继续让它自主；如果调整无效，介入指导</li><li><strong>利用 TodoWrite 日志</strong>：当 Claude 使用 TodoWrite 时，日志中会显示任务进度。这是了解它当前阶段的最佳窗口</li></ol><h2 id="_10-6-模型选择与-thinking-机制" tabindex="-1">10.6 模型选择与 Thinking 机制 <a class="header-anchor" href="#_10-6-模型选择与-thinking-机制" aria-label="Permalink to “10.6 模型选择与 Thinking 机制”">​</a></h2><p>工具系统决定了 Claude Code 能&quot;做什么&quot;，而模型决定了它能&quot;做得多好&quot;。同样的 Agent Loop，用不同的模型跑，结果可能天差地别。</p><h3 id="可用模型" tabindex="-1">可用模型 <a class="header-anchor" href="#可用模型" aria-label="Permalink to “可用模型”">​</a></h3><p>Claude Code 支持多模型切换，当前可用的模型包括：</p><table tabindex="0"><thead><tr><th>模型</th><th>定位</th><th>推理能力</th><th>响应速度</th><th>最佳场景</th></tr></thead><tbody><tr><td><strong>Opus 4.7</strong></td><td>旗舰</td><td>最强</td><td>较慢</td><td>复杂架构设计、大规模重构、深度代码分析</td></tr><tr><td><strong>Sonnet 4.6</strong></td><td>主力</td><td>强</td><td>中等</td><td>日常编程、代码审查、Bug 修复 —— <strong>推荐默认</strong></td></tr><tr><td><strong>Haiku 4.5</strong></td><td>轻量</td><td>一般</td><td>最快</td><td>简单问答、格式化、注释生成</td></tr><tr><td><strong>DeepSeek V4 Pro</strong></td><td>替代旗舰</td><td>强</td><td>中等偏慢</td><td>复杂任务的经济选择</td></tr><tr><td><strong>DeepSeek V4 Flash</strong></td><td>替代轻量</td><td>中等</td><td>快</td><td>日常任务的性价比选择</td></tr></tbody></table><p><strong>模型选择对 Agent Loop 的影响</strong>：</p><ul><li><strong>计划质量</strong>：Opus 制定的计划通常更周全（更少遗漏、更合理的步骤顺序），减少不必要的循环迭代</li><li><strong>工具选择准确性</strong>：更强的模型更少出现&quot;用错工具&quot;的情况——比如不会用 Read 去搜索代码</li><li><strong>自我纠正能力</strong>：Opus 在发现错误后能更快地调整策略，而 Haiku 可能需要更多次迭代</li><li><strong>代码生成质量</strong>：同样的 Edit 操作，Opus 生成的代码通常更符合项目风格、考虑更多边界情况</li></ul><h3 id="模型选择的决策框架" tabindex="-1">模型选择的决策框架 <a class="header-anchor" href="#模型选择的决策框架" aria-label="Permalink to “模型选择的决策框架”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>任务类型                    推荐模型           备选模型</span></span>\n<span class="line"><span>─────────────────────────────────────────────────────</span></span>\n<span class="line"><span>简单问答 / 代码解释         Haiku / V4 Flash    Sonnet</span></span>\n<span class="line"><span>日常功能开发               Sonnet             Opus / V4 Pro</span></span>\n<span class="line"><span>Bug 修复（范围明确）        Sonnet             Opus</span></span>\n<span class="line"><span>Bug 修复（根因不明）        Opus               Sonnet</span></span>\n<span class="line"><span>架构设计 / 重构规划        Opus               Sonnet + thinking</span></span>\n<span class="line"><span>Code Review               Sonnet             Opus</span></span>\n<span class="line"><span>测试编写                   Sonnet             Haiku</span></span>\n<span class="line"><span>文档生成                   Sonnet / Haiku     —</span></span>\n<span class="line"><span>大量文件的批量修改          Opus               Sonnet + 分步</span></span></code></pre></div><h3 id="thinking-模式" tabindex="-1">Thinking 模式 <a class="header-anchor" href="#thinking-模式" aria-label="Permalink to “Thinking 模式”">​</a></h3><p>Claude Code 支持 <strong>Extended Thinking</strong>（深度思考模式）。这是 Claude 模型的一个独特能力——在进行复杂操作前，模型会进行额外的内部推理，这些推理<strong>不占用输出的 token 配额</strong>。</p><p><strong>Thinking 的工作原理</strong>：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>普通模式:</span></span>\n<span class="line"><span>你的提示 → [模型直接生成响应]</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Thinking 模式:</span></span>\n<span class="line"><span>你的提示 → [模型内部推理链] → [模型生成响应]</span></span>\n<span class="line"><span>              ↑</span></span>\n<span class="line"><span>         这部分你看不到（不占 output token）</span></span>\n<span class="line"><span>         但它让最终输出质量显著提升</span></span></code></pre></div><p><strong>Thinking 模式下的工具选择变化</strong>：</p><p>当 Thinking 激活时，Claude 在调用工具前会&quot;多想一步&quot;：</p><ul><li>这个工具是不是最优选择？有没有更高效的方式？</li><li>这个 Read 的 offset/limit 范围是否合理？</li><li>这次 Edit 会不会破坏其他地方的逻辑？</li><li>是否需要先用 Grep 确认影响面？</li></ul><p>结果就是：Thinking 模式下的工具调用<strong>更少但更精准</strong>。你可能看到 Claude 用 5 次工具调用完成 Sonnet 普通模式需要 10 次调用才能完成的任务。</p><p><strong>何时使用 Thinking</strong>：</p><ul><li>✅ 复杂重构（跨多个文件、涉及架构变更）</li><li>✅ 难以定位的 Bug（需要深度推理数据流）</li><li>✅ 新项目的架构设计（需要权衡多种方案）</li><li>✅ 你发现 Claude 频繁走弯路时（开启 thinking 让它慢下来多想）</li><li>❌ 简单的 CRUD 操作（浪费，增加延迟）</li><li>❌ 格式化、注释、文档生成（不需要深度推理）</li><li>❌ 你已经提供详细步骤的任务（不需要它自己想太多）</li></ul><h3 id="fast-mode" tabindex="-1">Fast Mode <a class="header-anchor" href="#fast-mode" aria-label="Permalink to “Fast Mode”">​</a></h3><p>VSCode 扩展支持 <strong>Fast Mode</strong>——通过 <code>/fast</code> 命令切换。Fast Mode 在 Opus 模型上提供更快的输出速度，代价是略低的推理深度。</p><p><strong>适用场景</strong>：你需要 Opus 的推理质量，但不需要最深的分析——比如已经明确了修改方案，只是需要 Opus 的执行质量来生成代码。</p><h3 id="模型对工具选择质量的实证影响" tabindex="-1">模型对工具选择质量的实证影响 <a class="header-anchor" href="#模型对工具选择质量的实证影响" aria-label="Permalink to “模型对工具选择质量的实证影响”">​</a></h3><p>在实际使用中，不同模型在工具使用上表现出明显的差异：</p><table tabindex="0"><thead><tr><th>指标</th><th>Opus</th><th>Sonnet</th><th>Haiku</th></tr></thead><tbody><tr><td>工具选择正确率</td><td>95%+</td><td>90%+</td><td>80%+</td></tr><tr><td>每次任务平均工具调用数</td><td>少</td><td>中等</td><td>多</td></tr><tr><td>遇到错误后自我纠正率</td><td>高</td><td>中高</td><td>中</td></tr><tr><td>重复调用率</td><td>低</td><td>低</td><td>中</td></tr><tr><td>适合的子代理任务</td><td>复杂分析</td><td>常规开发</td><td>简单搜索</td></tr></tbody></table><p>这个表揭示了一个重要洞察：<strong>更强的模型不仅代码质量更高，而且&quot;用得更省&quot;——更少的工具调用完成任务，更少的重复操作，更高的错误恢复率</strong>。这在你按 token 计费时尤其值得考虑。</p><h2 id="_10-7-关键设计原则" tabindex="-1">10.7 关键设计原则 <a class="header-anchor" href="#_10-7-关键设计原则" aria-label="Permalink to “10.7 关键设计原则”">​</a></h2><p>Claude Code 的行为不是随机的——它遵循一组设计原则。理解这些原则，你就能预测它的行为，也能在它&quot;违反&quot;原则时判断是 bug 还是另有原因。</p><h3 id="原则一-宁可不做也不错做-default-to-safety" tabindex="-1">原则一：宁可不做也不错做（Default to Safety） <a class="header-anchor" href="#原则一-宁可不做也不错做-default-to-safety" aria-label="Permalink to “原则一：宁可不做也不错做（Default to Safety）”">​</a></h3><blockquote><p>对于高风险操作，默认需要确认。</p></blockquote><p>这是 Claude Code 设计哲学的基石。它宁愿多弹一次确认窗拖慢你的节奏，也不希望一个误操作毁掉你的代码。</p><p>体现在：</p><ul><li>Bash <code>rm -rf</code> 执行前一定确认</li><li>Git push --force 一定确认</li><li>项目外文件访问一定确认</li><li>首次安装的插件需要权限审批</li></ul><p><strong>设计意图</strong>：AI 不应该被盲目信任。Claude Code 的设计者假设 Claude 可能犯错，所以把&quot;最终决定权&quot;保留给你。这不是对 AI 的不信任，而是对开发者负责。</p><h3 id="原则二-上下文优先-context-first" tabindex="-1">原则二：上下文优先（Context First） <a class="header-anchor" href="#原则二-上下文优先-context-first" aria-label="Permalink to “原则二：上下文优先（Context First）”">​</a></h3><blockquote><p>先读文件理解，再动手修改。</p></blockquote><p>Claude 不会在看到你的提示后立即开始写代码。它会先建立对目标代码的理解——读取相关文件、搜索调用关系、理解项目结构——然后才开始修改。</p><p>这解释了为什么即使你要求&quot;把 auth.ts 第 45 行的 <code>var</code> 改成 <code>const</code>&quot;这种一行修改，Claude 可能也会先 Read 整个文件。它不是在浪费 token，而是在确保自己理解了上下文后才动手。</p><p><strong>对你意味着</strong>：在 CLAUDE.md 和 Memory 中尽可能多地提供项目结构信息，减少 Claude &quot;探索&quot;所需的工具调用次数。</p><h3 id="原则三-渐进式变更-incremental-change" tabindex="-1">原则三：渐进式变更（Incremental Change） <a class="header-anchor" href="#原则三-渐进式变更-incremental-change" aria-label="Permalink to “原则三：渐进式变更（Incremental Change）”">​</a></h3><blockquote><p>小步迭代，而非一次性大改。</p></blockquote><p>Claude 倾向于把大的重构拆成多个小步骤，每步都验证确认后再继续。这不是效率低，而是：</p><ul><li>每个小步骤的风险可控</li><li>出错时回滚范围小</li><li>你可以在任意一步介入调整方向</li></ul><p><strong>对比</strong>：</p><ul><li>❌ &quot;一口气把 auth.ts 全部重写成 async/await&quot; → 200 行改动，一个 Edit，中间出错就全废</li><li>✅ &quot;先改 authenticate，验证；再改 refreshToken，验证；再改...&quot; → 10 个 Edit，每个都独立验证</li></ul><h3 id="原则四-可逆性考量-reversibility" tabindex="-1">原则四：可逆性考量（Reversibility） <a class="header-anchor" href="#原则四-可逆性考量-reversibility" aria-label="Permalink to “原则四：可逆性考量（Reversibility）”">​</a></h3><blockquote><p>优先选择可撤销的操作路径。</p></blockquote><p>当有多种方式完成任务时，Claude 倾向于选择更容易撤销的方式：</p><ul><li>优先用 Edit（可精确追踪改动）而非 Write（覆写整个文件）</li><li>优先用 Git 分支操作而非直接修改主干</li><li>优先生成新文件而非覆盖已有文件</li></ul><p><strong>对你意味着</strong>：在要求 Claude 做大规模改动前，建议它&quot;先新建一个分支&quot;或&quot;先备份原文件&quot;，这与 Claude 自身的设计偏好一致。</p><h3 id="原则五-透明化-transparency" tabindex="-1">原则五：透明化（Transparency） <a class="header-anchor" href="#原则五-透明化-transparency" aria-label="Permalink to “原则五：透明化（Transparency）”">​</a></h3><blockquote><p>所有工具调用和结果对你可见。</p></blockquote><p>Claude 不会背着你做任何事。每一次文件读取、每一次代码修改、每一次命令执行，都在聊天面板中有完整的日志记录。这不是技术限制，而是有意的设计选择——让你随时了解 Claude 在做什么、为什么这样做。</p><p>这与你使用其他 AI 工具（如 ChatGPT）的体验截然不同。ChatGPT 的&quot;思考过程&quot;是黑盒的，而 Claude Code 通过工具调用日志把整个执行链<strong>白盒化</strong>。</p><h3 id="原则六-工具最小化-minimal-tool-use" tabindex="-1">原则六：工具最小化（Minimal Tool Use） <a class="header-anchor" href="#原则六-工具最小化-minimal-tool-use" aria-label="Permalink to “原则六：工具最小化（Minimal Tool Use）”">​</a></h3><blockquote><p>用最少的工具调用完成任务。</p></blockquote><p>Claude 被训练为选择最高效的工具组合。如果一次 Grep 就能找到目标，它不会先 Glob 再逐个 Read；如果一次 Edit 能覆盖修改范围，它不会拆成 5 次。但&quot;最少&quot;不等于&quot;省 token&quot;——Claude 不会为了省一次 Read 而去猜代码内容，那会违反原则二（上下文优先）。</p><h3 id="原则七-自我纠正-self-correction" tabindex="-1">原则七：自我纠正（Self-Correction） <a class="header-anchor" href="#原则七-自我纠正-self-correction" aria-label="Permalink to “原则七：自我纠正（Self-Correction）”">​</a></h3><blockquote><p>读取自己的输出，发现并修复错误。</p></blockquote><p>Claude 在完成修改后，几乎总是会重新 Read 修改过的文件来验证。如果发现错误——比如编辑没有正确应用、缩进不对、漏了某个条件——它会主动修复。</p><p>这不是 Claude &quot;不自信&quot;，而是设计上鼓励的自检行为。你应该把这种&quot;回头看&quot;视为质量信号——如果 Claude 改完代码后没有再读取验证，那才值得警惕。</p><h3 id="原则的优先级与冲突" tabindex="-1">原则的优先级与冲突 <a class="header-anchor" href="#原则的优先级与冲突" aria-label="Permalink to “原则的优先级与冲突”">​</a></h3><p>这七条原则不是平行的。当它们发生冲突时，优先级是：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>安全性（原则一）&gt; 上下文准确性（原则二）&gt; 可逆性（原则四）&gt; 渐进性（原则三）&gt; 透明性（原则五）&gt; 自我纠正（原则七）&gt; 效率（原则六）</span></span></code></pre></div><p>理解这个优先级，你就能解释 Claude Code 的一些&quot;看似矛盾&quot;的行为：为什么 Claude 能在某些场景下选择 Write 而非 Edit？因为在这个场景下，Write 反而更可逆（原则四覆盖了原则六）。</p><h2 id="_10-8-本章小结" tabindex="-1">10.8 本章小结 <a class="header-anchor" href="#_10-8-本章小结" aria-label="Permalink to “10.8 本章小结”">​</a></h2><p>本章深入剖析了 Claude Code 的内部工作机制。以下是核心要点：</p><p><strong>Agent Loop</strong>：Claude Code 通过&quot;理解意图 → 制定计划 → 调用工具 → 观察结果 → 迭代&quot;的循环完成所有任务。你在这个循环中扮演启动者、监督者和验收者三个角色。理解循环的每个阶段，你就能预测 Claude 的行为。</p><p><strong>工具系统</strong>：Claude Code 拥有 13 个核心工具，分为文件工具（Read/Write/Edit/Bash/Glob/Grep）和高级工具（Agent/WebSearch/WebFetch/TodoWrite/TaskOutput/NotebookEdit/Task）。每个工具有其特定的触发条件、使用方式和限制。学会阅读工具调用日志，你能判断 Claude 的工作状态是否健康。</p><p><strong>完整生命周期</strong>：从你发出提示到 Claude 给出结果，中间经历了上下文收集、意图理解、计划制定、多轮工具调用、自我验证等至少 10 个步骤。理解这个流程，你就知道在哪些节点介入最有效。</p><p><strong>模型与 Thinking</strong>：不同模型的推理能力直接影响工具选择质量、计划质量和自我纠正能力。Thinking 模式通过内部推理提升工具调用的精准度。选择合适的模型组合可以显著提升效率。</p><p><strong>设计原则</strong>：宁可不做也不错做、上下文优先、渐进式变更、可逆性考量、透明化、工具最小化、自我纠正——这七条原则共同定义了 Claude Code 的行为模式。把它们内化为你的心智模型，你就能从&quot;会用 Claude Code&quot;升级为&quot;精通 Claude Code&quot;。</p><hr><p>从本章开始，后续章节将逐一深入本章提到的每个核心系统：第 11 章深入上下文管理的细节，第 12 章学习如何编写 CLAUDE.md 来最大化 Claude 的理解能力，第 13 章完整解析四层配置体系，第 14 章掌握权限系统的进阶用法。</p>',182))])}]]);export{r as __pageData,c as default};
